sql:
SELECT team_member
FROM sales_team
ORDER BY team_member ASC;

SELECT team_member
FROM sales_team
ORDER BY team_member;

SELECT COUNT(*) AS total_quotes
FROM quotes
WHERE quote_date BETWEEN '2019-04-01' AND '2019-06-30';

